#include <stdio.h>
#define N 3

void simulate_sjf(int burst[], int n, int wait[], int turnaround[]) {
    int sorted[N];
    for (int i = 0; i < n; i++) sorted[i] = burst[i];
    for (int i = 0; i < n - 1; i++)
        for (int j = 0; j < n - 1 - i; j++)
            if (sorted[j] > sorted[j+1]) {
                int tmp = sorted[j]; sorted[j] = sorted[j+1]; sorted[j+1] = tmp;
            }
    wait[0] = 0;
    for (int i = 1; i < n; i++)
        wait[i] = wait[i-1] + sorted[i-1];
    for (int i = 0; i < n; i++)
        turnaround[i] = wait[i] + sorted[i];
}

int main(void) {
    {
        int burst[] = {5};
        int wait[1], ta[1];
        simulate_sjf(burst, 1, wait, ta);
        printf("%d\n", (int)(wait[0]));
        printf("%d\n", (int)(ta[0]));
    }
    {
        int burst[] = {3, 3};
        int wait[2], ta[2];
        simulate_sjf(burst, 2, wait, ta);
        printf("%d\n", (int)(wait[0]));
        printf("%d\n", (int)(wait[1]));
        printf("%d\n", (int)(ta[0]));
        printf("%d\n", (int)(ta[1]));
    }
    {
        int burst[] = {6, 3, 9};
        int wait[3], ta[3];
        simulate_sjf(burst, 3, wait, ta);
        /* After sort: {3,6,9} */
        printf("%d\n", (int)(wait[0]));
        printf("%d\n", (int)(wait[1]));
        printf("%d\n", (int)(wait[2]));
    }
    {
        int burst[] = {8, 2, 5};
        int wait[3], ta[3];
        simulate_sjf(burst, 3, wait, ta);
        /* After sort: {2,5,8} */
        printf("%d\n", (int)(wait[0]));
        printf("%d\n", (int)(wait[1]));
        printf("%d\n", (int)(wait[2]));
    }
    return 0;
}

